import{_ as o,o as t,c as s,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Remote Control","description":"","frontmatter":{"summary":"macOS app flow for controlling a remote OpenSoul gateway over SSH","read_when":["Setting up or debugging remote mac control"],"title":"Remote Control"},"headers":[],"relativePath":"platforms/mac/remote.md","filePath":"platforms/mac/remote.md","lastUpdated":1771906665000}'),n={name:"platforms/mac/remote.md"};function i(r,e,l,h,c,d){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="remote-opensoul-macos-⇄-remote-host" tabindex="-1"><a class="header-anchor" href="#remote-opensoul-macos-⇄-remote-host">#</a> Remote OpenSoul (macOS ⇄ remote host)</h1><p>This flow lets the macOS app act as a full remote control for a OpenSoul gateway running on another host (desktop/server). It’s the app’s <strong>Remote over SSH</strong> (remote run) feature. All features—health checks, Voice Wake forwarding, and Web Chat—reuse the same remote SSH configuration from <em>Settings → General</em>.</p><h2 id="modes" tabindex="-1"><a class="header-anchor" href="#modes">#</a> Modes</h2><ul><li><strong>Local (this Mac)</strong>: Everything runs on the laptop. No SSH involved.</li><li><strong>Remote over SSH (default)</strong>: OpenSoul commands are executed on the remote host. The mac app opens an SSH connection with <code>-o BatchMode</code> plus your chosen identity/key and a local port-forward.</li><li><strong>Remote direct (ws/wss)</strong>: No SSH tunnel. The mac app connects to the gateway URL directly (for example, via Tailscale Serve or a public HTTPS reverse proxy).</li></ul><h2 id="remote-transports" tabindex="-1"><a class="header-anchor" href="#remote-transports">#</a> Remote transports</h2><p>Remote mode supports two transports:</p><ul><li><strong>SSH tunnel</strong> (default): Uses <code>ssh -N -L ...</code> to forward the gateway port to localhost. The gateway will see the node’s IP as <code>127.0.0.1</code> because the tunnel is loopback.</li><li><strong>Direct (ws/wss)</strong>: Connects straight to the gateway URL. The gateway sees the real client IP.</li></ul><h2 id="prereqs-on-the-remote-host" tabindex="-1"><a class="header-anchor" href="#prereqs-on-the-remote-host">#</a> Prereqs on the remote host</h2><ol><li>Install Node + pnpm and build/install the OpenSoul CLI (<code>pnpm install &amp;&amp; pnpm build &amp;&amp; pnpm link --global</code>).</li><li>Ensure <code>opensoul</code> is on PATH for non-interactive shells (symlink into <code>/usr/local/bin</code> or <code>/opt/homebrew/bin</code> if needed).</li><li>Open SSH with key auth. We recommend <strong>Tailscale</strong> IPs for stable reachability off-LAN.</li></ol><h2 id="macos-app-setup" tabindex="-1"><a class="header-anchor" href="#macos-app-setup">#</a> macOS app setup</h2><ol><li>Open <em>Settings → General</em>.</li><li>Under <strong>OpenSoul runs</strong>, pick <strong>Remote over SSH</strong> and set: <ul><li><strong>Transport</strong>: <strong>SSH tunnel</strong> or <strong>Direct (ws/wss)</strong>.</li><li><strong>SSH target</strong>: <code>user@host</code> (optional <code>:port</code>). <ul><li>If the gateway is on the same LAN and advertises Bonjour, pick it from the discovered list to auto-fill this field.</li></ul></li><li><strong>Gateway URL</strong> (Direct only): <code>wss://gateway.example.ts.net</code> (or <code>ws://...</code> for local/LAN).</li><li><strong>Identity file</strong> (advanced): path to your key.</li><li><strong>Project root</strong> (advanced): remote checkout path used for commands.</li><li><strong>CLI path</strong> (advanced): optional path to a runnable <code>opensoul</code> entrypoint/binary (auto-filled when advertised).</li></ul></li><li>Hit <strong>Test remote</strong>. Success indicates the remote <code>opensoul status --json</code> runs correctly. Failures usually mean PATH/CLI issues; exit 127 means the CLI isn’t found remotely.</li><li>Health checks and Web Chat will now run through this SSH tunnel automatically.</li></ol><h2 id="web-chat" tabindex="-1"><a class="header-anchor" href="#web-chat">#</a> Web Chat</h2><ul><li><strong>SSH tunnel</strong>: Web Chat connects to the gateway over the forwarded WebSocket control port (default 18789).</li><li><strong>Direct (ws/wss)</strong>: Web Chat connects straight to the configured gateway URL.</li><li>There is no separate WebChat HTTP server anymore.</li></ul><h2 id="permissions" tabindex="-1"><a class="header-anchor" href="#permissions">#</a> Permissions</h2><ul><li>The remote host needs the same TCC approvals as local (Automation, Accessibility, Screen Recording, Microphone, Speech Recognition, Notifications). Run onboarding on that machine to grant them once.</li><li>Nodes advertise their permission state via <code>node.list</code> / <code>node.describe</code> so agents know what’s available.</li></ul><h2 id="security-notes" tabindex="-1"><a class="header-anchor" href="#security-notes">#</a> Security notes</h2><ul><li>Prefer loopback binds on the remote host and connect via SSH or Tailscale.</li><li>If you bind the Gateway to a non-loopback interface, require token/password auth.</li><li>See <a href="/docs/gateway/security/index">Security</a> and <a href="/docs/gateway/tailscale">Tailscale</a>.</li></ul><h2 id="whatsapp-login-flow-remote" tabindex="-1"><a class="header-anchor" href="#whatsapp-login-flow-remote">#</a> WhatsApp login flow (remote)</h2><ul><li>Run <code>opensoul channels login --verbose</code> <strong>on the remote host</strong>. Scan the QR with WhatsApp on your phone.</li><li>Re-run login on that host if auth expires. Health check will surface link problems.</li></ul><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting">#</a> Troubleshooting</h2><ul><li><strong>exit 127 / not found</strong>: <code>opensoul</code> isn’t on PATH for non-login shells. Add it to <code>/etc/paths</code>, your shell rc, or symlink into <code>/usr/local/bin</code>/<code>/opt/homebrew/bin</code>.</li><li><strong>Health probe failed</strong>: check SSH reachability, PATH, and that Baileys is logged in (<code>opensoul status --json</code>).</li><li><strong>Web Chat stuck</strong>: confirm the gateway is running on the remote host and the forwarded port matches the gateway WS port; the UI requires a healthy WS connection.</li><li><strong>Node IP shows 127.0.0.1</strong>: expected with the SSH tunnel. Switch <strong>Transport</strong> to <strong>Direct (ws/wss)</strong> if you want the gateway to see the real client IP.</li><li><strong>Voice Wake</strong>: trigger phrases are forwarded automatically in remote mode; no separate forwarder is needed.</li></ul><h2 id="notification-sounds" tabindex="-1"><a class="header-anchor" href="#notification-sounds">#</a> Notification sounds</h2><p>Pick sounds per notification from scripts with <code>opensoul</code> and <code>node.invoke</code>, e.g.:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> notify</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Ping&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --body</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Remote gateway ready&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sound</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Glass</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>There is no global “default sound” toggle in the app anymore; callers choose a sound (or none) per request.</p>',25)])])}const g=o(n,[["render",i]]);export{u as __pageData,g as default};
